package ServerSequenceModel {
	private import ScalarValues::String;
	public import SignalDefinitions::*;

	package SignalDefinitions {
	    item def Subscribe {
	    	attribute topic : String;
	    	ref part subscriber;
	    }

		item def Publish {
			attribute topic : String;
			ref publication;
		}

		item def Deliver {
			ref publication;
		}
	}

	part def PubSubSequence {
		part producer[1] {
			event occurrence publish_source_event;
		}

		message publish_message from producer.publish_source_event to server.publish_target_event;

		part server[1] {
			event occurrence subscribe_target_event;
			then event occurrence publish_target_event;
			then event occurrence deliver_source_event;
		}

		message subscribe_message from consumer.subscribe_source_event to server.subscribe_target_event;
		message deliver_message from server.deliver_source_event to consumer.deliver_target_event;

		part consumer {
			event occurrence subscribe_source_event;
			then event occurrence deliver_target_event;
		}
	}
}

package MassConstraintExample {
	private import ISQ::*;
	private import SI::*;
	private import NumericalFunctions::*;

	part def Engine {
		attribute m :> mass;
	}

	part def Transmission {
		attribute m :> mass;
	}

	part def Vehicle1 {
		attribute m : MassValue = eng.m + trans.m;

		part eng : Engine {
			attribute :>> m : MassValue;
		}

		part trans : Transmission {
			attribute :>> m : MassValue;
		}
	}

	part def Vehicle2 {
		assert constraint { m == eng.m + trans.m }

		attribute m : MassValue;

		part eng : Engine {
			attribute :>> m : MassValue;
		}

		part trans : Transmission {
			attribute :>> m : MassValue;
		}
	}

	constraint def MassConstraint3 {
		in totalMass : MassValue; 
		in partMasses : MassValue[0..*];

		totalMass == sum(partMasses)
	}

	part def Vehicle3 {
		assert constraint massConstraint : MassConstraint3 {
			in totalMass = m;
			in partMasses = (eng.m, trans.m);
		}

		attribute m : MassValue;

		part eng {
			attribute m : MassValue;
		}

		part trans {
			attribute m : MassValue;
		}
	}

	constraint def MassConstraint4 {
		in totalMass : MassValue;
		in partMasses : MassValue[0..*];
	}

	constraint mc : MassConstraint4 {
		in totalMass : MassValue; 
		in partMasses : MassValue[0..*];

		totalMass == sum(partMasses)
	}

	part def Vehicle4 {
		assert mc {
			in totalMass = m;
			in partMasses = (eng.m, trans.m);
		}

		attribute m : MassValue;

		part eng : Engine {
			attribute :>> m : MassValue;
		}

		part trans : Transmission {
			attribute :>> m : MassValue;
		}
	}

	constraint def MassLimit {
		in mass : MassValue; 
		in maxMass : MassValue;

		mass <= maxMass
	}

	part def Vehicle5 {
		assert constraint ml : MassLimit {
			in mass = m;
			in maxMass = 2500 [kg];
		}

		attribute m : MassValue = eng.m + trans.m;

		part eng : Engine {
			attribute :>> m : MassValue;
		}

		part trans : Transmission {
			attribute :>> m : MassValue;
		}
	}	

}

package MassRollup {
	private import NumericalFunctions::*;

	part def MassedThing {
		attribute mass :> ISQ::mass; 
		attribute totalMass :> ISQ::mass;
	}

	part simpleThing : MassedThing {
		attribute redefines totalMass = mass;
	}

	part compositeThing : MassedThing {
		part subcomponents: MassedThing[*];

		attribute redefines totalMass default
			mass + sum(subcomponents.totalMass); 
	}

	part filteredMassThing :> compositeThing {
		abstract attribute minMass :> ISQ::mass;

		attribute redefines totalMass =
			mass + sum(subcomponents.totalMass.?{in p :> ISQ::mass; p > minMass});
	}

}

