package StateTest {
	attribute def Sig {
		x;
	}
	attribute def Exit;

	part p;

	action act;

	state def S {
		do action A;
		entry; then S1;

		state S1;
			accept s : Sig
			do action D
			then S2;

		state S2 {
			do send new Sig(T.s.x) to p;
			state S3;
		}
		accept Exit then done;

		transition
			first S1
			accept s : Sig
			do action D
			then S2.S3;

		transition T
			first S2.S3
			accept s : Sig via p
			if true
			do send s to p
			then S1;

		exit act;

		state S3 {
			state S3a;
		}

		transition first S3.S3a then S1; 
	}

	state s0 {
  		state s1 {
    		state s2;
  		}
  		state s3 {
  			state s4;
  		}
  		transition t1 first s1.s2 then s3.s4;
	}

	state s parallel {
		state s1;
		state s2;
	}

	state s4 {
		do action a;
  		action c;
	}

	state s5 :> s4 {
  		do action b :>> c;
	}

}

package StructuredControlTest {

	action {
		attribute i : ScalarValues::Integer := 0;
		attribute b : ScalarValues::Boolean;

		if i < 0 {
			assign i := 0;
		} else if i == 0 {
			assign i := 1;
		} else {
			assign i := i + 1;
		}

		if i > 0 {
			assign i := i + 1;
		}

		then action aLoop
		while i > 0 {
			assign i := i - 1;
		} until b;

		then while i > 0 {
			assign i := i - 1;
		}

		loop {
			assign i := i - 1;
		} until b;

		for n : ScalarValues::Integer in (1, 2, 3) {
			assign i := i * n;
		}
	}
}

